@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --color-brand: var(--brand);
  --color-brand-foreground: var(--brand-foreground);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

:root {
  --radius: 0.5rem;
  --background: oklch(0.99 0.002 264);
  --foreground: oklch(0.18 0.02 264);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.18 0.02 264);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.18 0.02 264);
  --primary: oklch(0.45 0.2 264);
  --primary-foreground: oklch(0.99 0.002 264);
  --secondary: oklch(0.96 0.01 264);
  --secondary-foreground: oklch(0.3 0.05 264);
  --muted: oklch(0.96 0.01 264);
  --muted-foreground: oklch(0.5 0.03 264);
  --accent: oklch(0.94 0.02 264);
  --accent-foreground: oklch(0.3 0.05 264);
  --destructive: oklch(0.55 0.22 25);
  --border: oklch(0.9 0.01 264);
  --input: oklch(0.9 0.01 264);
  --ring: oklch(0.55 0.15 264);
  --brand: oklch(0.5 0.22 264);
  --brand-foreground: oklch(0.99 0.002 264);
  --chart-1: oklch(0.55 0.2 264);
  --chart-2: oklch(0.6 0.15 200);
  --chart-3: oklch(0.65 0.12 150);
  --chart-4: oklch(0.7 0.18 80);
  --chart-5: oklch(0.6 0.2 30);
  --sidebar: oklch(0.98 0.005 264);
  --sidebar-foreground: oklch(0.18 0.02 264);
  --sidebar-primary: oklch(0.45 0.2 264);
  --sidebar-primary-foreground: oklch(0.99 0.002 264);
  --sidebar-accent: oklch(0.94 0.02 264);
  --sidebar-accent-foreground: oklch(0.3 0.05 264);
  --sidebar-border: oklch(0.9 0.01 264);
  --sidebar-ring: oklch(0.55 0.15 264);
}

.dark {
  --background: oklch(0.14 0.02 264);
  --foreground: oklch(0.97 0.005 264);
  --card: oklch(0.18 0.025 264);
  --card-foreground: oklch(0.97 0.005 264);
  --popover: oklch(0.18 0.025 264);
  --popover-foreground: oklch(0.97 0.005 264);
  --primary: oklch(0.65 0.18 264);
  --primary-foreground: oklch(0.14 0.02 264);
  --secondary: oklch(0.24 0.03 264);
  --secondary-foreground: oklch(0.97 0.005 264);
  --muted: oklch(0.24 0.03 264);
  --muted-foreground: oklch(0.65 0.04 264);
  --accent: oklch(0.26 0.04 264);
  --accent-foreground: oklch(0.97 0.005 264);
  --destructive: oklch(0.6 0.2 25);
  --border: oklch(0.28 0.03 264);
  --input: oklch(0.28 0.03 264);
  --ring: oklch(0.55 0.15 264);
  --brand: oklch(0.6 0.2 264);
  --brand-foreground: oklch(0.14 0.02 264);
  --chart-1: oklch(0.6 0.2 264);
  --chart-2: oklch(0.65 0.15 200);
  --chart-3: oklch(0.7 0.12 150);
  --chart-4: oklch(0.75 0.18 80);
  --chart-5: oklch(0.65 0.2 30);
  --sidebar: oklch(0.16 0.025 264);
  --sidebar-foreground: oklch(0.97 0.005 264);
  --sidebar-primary: oklch(0.6 0.2 264);
  --sidebar-primary-foreground: oklch(0.97 0.005 264);
  --sidebar-accent: oklch(0.24 0.03 264);
  --sidebar-accent-foreground: oklch(0.97 0.005 264);
  --sidebar-border: oklch(0.28 0.03 264);
  --sidebar-ring: oklch(0.55 0.15 264);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}
